import React, { useState } from 'react';
import {
  Box,
  Container,
  Typography,
  TextField,
  Button,
  Paper,
  Stepper,
  Step,
  StepLabel,
  CircularProgress,
  Fade,
  Divider,
  Alert
} from '@mui/material';
import { useNavigate } from 'react-router-dom';
import CheckCircleOutlineIcon from '@mui/icons-material/CheckCircleOutline';

const EnhancePage = () => {
  const navigate = useNavigate();
  const [activeStep, setActiveStep] = useState(0);
  const [loading, setLoading] = useState(false);
  const [complete, setComplete] = useState(false);
  const [formData, setFormData] = useState({
    clientName: '',
    clientEmail: '',
    clientCompany: '',
    clientTitle: '',
    testimonial: '',
    enhancedTestimonial: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleEnhance = () => {
    setLoading(true);

    // Simulate API call to enhance testimonial
    setTimeout(() => {
      const enhanced = `Working with ${formData.clientName} was incredible! Their ${formData.testimonial} was just the beginning. They achieved remarkable results, showing a deep understanding of our needs and delivering beyond expectations. I highly recommend their services to anyone looking for exceptional quality and professionalism.`;

      setFormData({
        ...formData,
        enhancedTestimonial: enhanced
      });

      setLoading(false);
      setActiveStep(1);
    }, 2000);
  };

  const handleSubmit = () => {
    setLoading(true);

    // Simulate API call to save testimonial and send verification email
    setTimeout(() => {
      setLoading(false);
      setComplete(true);
    }, 1500);
  };

  const steps = ['Enhance Testimonial', 'Review & Submit'];

  return (
    <Container maxWidth="md" sx={{ py: 6 }}>
      <Typography variant="h4" align="center" fontWeight="bold" gutterBottom>
        Create Powerful Testimonials
      </Typography>
      <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 4 }}>
        Transform basic feedback into compelling testimonials that convert
      </Typography>

      <Paper elevation={0} sx={{ p: 4, borderRadius: 3, boxShadow: '0 4px 20px rgba(0,0,0,0.08)' }}>
        <Stepper activeStep={activeStep} sx={{ mb: 4 }}>
          {steps.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>

        {!complete ? (
          <>
            {activeStep === 0 ? (
              <Box>
                <Typography variant="h6" gutterBottom>Client Information</Typography>
                <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
                  <TextField
                    fullWidth
                    label="Client Name"
                    name="clientName"
                    value={formData.clientName}
                    onChange={handleChange}
                    required
                  />
                  <TextField
                    fullWidth
                    label="Client Email"
                    name="clientEmail"
                    type="email"
                    value={formData.clientEmail}
                    onChange={handleChange}
                    required
                  />
                </Box>

                <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
                  <TextField
                    fullWidth
                    label="Company"
                    name="clientCompany"
                    value={formData.clientCompany}
                    onChange={handleChange}
                  />
                  <TextField
                    fullWidth
                    label="Title/Position"
                    name="clientTitle"
                    value={formData.clientTitle}
                    onChange={handleChange}
                  />
                </Box>

                <Typography variant="h6" gutterBottom>Raw Testimonial</Typography>
                <Alert severity="info" sx={{ mb: 2 }}>
                  Enter the original testimonial from your client. Our AI will enhance it while maintaining authenticity.
                </Alert>
                <TextField
                  fullWidth
                  multiline
                  rows={4}
                  label="Original Testimonial"
                  name="testimonial"
                  value={formData.testimonial}
                  onChange={handleChange}
                  placeholder="E.g., The service was good. I liked working with them."
                  required
                  sx={{ mb: 3 }}
                />

                <Box sx={{ display: 'flex', justifyContent: 'flex-end' }}>
                  <Button
                    variant="contained"
                    color="primary"
                    size="large"
                    onClick={handleEnhance}
                    disabled={!formData.clientName || !formData.clientEmail || !formData.testimonial || loading}
                    sx={{ px: 4 }}
                  >
                    {loading ? <CircularProgress size={24} /> : 'Enhance Testimonial'}
                  </Button>
                </Box>
              </Box>
            ) : (
              <Box>
                <Typography variant="h6" gutterBottom>Enhanced Testimonial</Typography>
                <Alert severity="success" sx={{ mb: 2 }}>
                  Your testimonial has been enhanced! Review it below and make any edits before submitting.
                </Alert>
                <TextField
                  fullWidth
                  multiline
                  rows={6}
                  label="Enhanced Testimonial"
                  name="enhancedTestimonial"
                  value={formData.enhancedTestimonial}
                  onChange={handleChange}
                  sx={{ mb: 4 }}
                />

                <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                  We'll send an email to {formData.clientEmail} asking them to verify this testimonial.
                </Typography>

                <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                  <Button
                    variant="outlined"
                    onClick={() => setActiveStep(0)}
                    sx={{ px: 3 }}
                  >
                    Back
                  </Button>
                  <Button
                    variant="contained"
                    color="primary"
                    size="large"
                    onClick={handleSubmit}
                    disabled={loading}
                    sx={{ px: 4 }}
                  >
                    {loading ? <CircularProgress size={24} /> : 'Submit & Send for Verification'}
                  </Button>
                </Box>
              </Box>
            )}
          </>
        ) : (
          <Fade in={complete}>
            <Box sx={{ textAlign: 'center', py: 4 }}>
              <CheckCircleOutlineIcon color="success" sx={{ fontSize: 64, mb: 2 }} />
              <Typography variant="h5" gutterBottom>
                Testimonial Created Successfully!
              </Typography>
              <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
                We've sent a verification email to {formData.clientEmail}. Once verified, your testimonial will be ready to share.
              </Typography>
              <Button
                variant="contained"
                color="primary"
                size="large"
                onClick={() => navigate('/dashboard')}
                sx={{ px: 4 }}
              >
                Go to Dashboard
              </Button>
            </Box>
          </Fade>
        )}
      </Paper>
    </Container>
  );
};

export default EnhancePage;
